  Resumen: En este programa crearemos una alarma anti-intrusos con el sensor de movimiento HC-SR501
  y un zumbador. La alarma se activa al detectar movimiento y para desactivarla debemos oprimir un
  botón.
*/
/**
  definición de pines
*/
const int ledpin = 13;
const int pirpin = 12;
const int buzzerpin = 11;
const int buttonpin = 10;
/**
  variable que almacena el ultimo estado del pin
*/
int ultimoestado = LOW;
/**
  variable que indica si la alarma está activada o no
*/
bool alarm = false;
/**
  variable usada para alternar el encendido / apagado del buzzer
*/
uint32_t tiempobuzzer = 0;
/**
  Función setup: se ejecuta una vez cuando encendemos el arduino
*/
void setup() {
  // preparar la comunicación serial
  Serial.begin(115200);
  // mostrar mensaje inicial
  Serial.println(F("----------------------------------------------------"));
  Serial.println(F("      EJEMPLO SENSOR DE MOVIMIENTO PIR HC-SR501     "));
  Serial.println(F("            https://www.geekfactory.mx              "));
  Serial.println(F("----------------------------------------------------"));
  // configurar los pines de entrada / salida
  pinMode(pirpin, INPUT);
  pinMode(ledpin, OUTPUT);
  pinMode(buzzerpin, OUTPUT);
  pinMode(buttonpin, INPUT_PULLUP);
}
/**
  Función loop: se ejecuta continuamente mientras el arduino permanece encendido
*/
void loop() {
  // leer el estado del pin donde está conectado el sensor PIR
  int estado = digitalRead(pirpin);
  /**
  detectamos cuando el pin cambió de estado, esto nos permite solamente enviar mensajes
  a la interfaz serie cuando cambia el estado del pin conectado al sensor
  */
  if (estado != ultimoestado) {
    // actualizar la variable para detectar cambios
    ultimoestado = estado;
    if (estado == HIGH) {
      // al detectar un pulso en alto es que el sensor detectó movimiento
      Serial.println(F("Movimiento detectado"));
      digitalWrite(ledpin, HIGH);
      // activar el sonido de la alarma
      if (!alarm) {
        alarm = true;
        tiempobuzzer = millis();
        Serial.println(F("ALARMA ACTIVADA"));
      }
    } else {
      // el estado bajo en el pin del sensor significa que no hay detección
      Serial.println(F("Sensor en reposo..."));
      digitalWrite(ledpin, LOW);
    }
  }
  /**
  Si la alarma esta activada generamos una señal alternante en el pin donde se
  encuentra conectado el buzzer, usamos la función millis() para evitar el uso de
  retardos (delay).
  */
  if (alarm) {
    uint32_t ahora = millis();
    if (ahora - tiempobuzzer >= 500) {
      // alternar el estado del pin
      digitalWrite(buzzerpin, !digitalRead(buzzerpin));
      tiempobuzzer = ahora;
    }
  }
  /**
  Revisar el estado del botón para desactivación de la alarma, si se oprime el botón
  apagamos el sonido y nos aseguramos que el zumbador quede desactivado.
  */
  if (LOW == digitalRead(buttonpin)) {
    // retardo para rebotes y ruido
    delay(20);
    // revisar nuevamente el estado del pin
    if (LOW == digitalRead(buttonpin)) {
      // solo imprimir mensaje si la alarma esta activada
      if (alarm)
        Serial.println(F("ALARMA DESACTIVADA"));
      // desactivar rutina del sonido
      alarm = false;
      // y asegurarnos que se apague el buzzer
      digitalWrite(buzzerpin, LOW);
    }
  }
